const input = $json || {};
const query = input.query || input;
return [{
  json: {
    job_id: String(query.job || '').trim(),
    token: String(query.token || '').trim(),
    kind: String(query.kind || 'summary').trim().toLowerCase(),
  },
}];

const d = $('Normalize Report Request').first().json || {};
const esc = (value) => String(value === undefined || value === null ? '' : value).replace(/'/g, "''");
const kinds = new Set(['summary', 'valid', 'ambiguous', 'invalid', 'applied']);
const kind = kinds.has(d.kind) ? d.kind : 'summary';
let sql = '';
if (!d.job_id || !d.token) {
  sql = "SELECT 'error' AS section, 'missing report token or job id' AS message;";
} else if (kind === 'summary') {
  sql = "SELECT 'summary' AS section, job_id, status, total_rows, valid_rows, invalid_rows, ambiguous_rows, matched_rows, new_rows, applied_rows, failed_rows, file_name, source_type, source_ref FROM public.owner_import_jobs WHERE job_id = '" + esc(d.job_id) + "' AND report_token = '" + esc(d.token) + "' LIMIT 1;";
} else {
  sql = "WITH job AS (SELECT job_id FROM public.owner_import_jobs WHERE job_id = '" + esc(d.job_id) + "' AND report_token = '" + esc(d.token) + "' LIMIT 1) SELECT '" + kind + "' AS section, r.row_no, r.chunk_no, r.match_status, r.apply_status, COALESCE(r.target_sku, '') AS target_sku, COALESCE(r.target_item_name, '') AS target_item_name, COALESCE(r.error_reason, '') AS error_reason, COALESCE(r.review_reason, '') AS review_reason, COALESCE(r.normalized_payload_json->>'item_name', '') AS item_name, COALESCE(r.normalized_payload_json->>'price', '') AS price, COALESCE(r.normalized_payload_json->>'stock', '') AS stock FROM public.owner_import_job_rows r WHERE r.job_id = (SELECT job_id FROM job) AND " + (kind === 'valid' ? "r.match_status IN ('new','matched')" : kind === 'ambiguous' ? "r.match_status = 'ambiguous'" : kind === 'invalid' ? "r.match_status = 'invalid'" : "r.apply_status = 'applied'") + " ORDER BY r.row_no ASC;";
}
return [{ json: { ...d, sql } }];

const d = $('Normalize Report Request').first().json || {};
const rows = $input.all().map((item) => item.json || {});
const kind = String(d.kind || 'summary');
let csv = '';
let fileName = 'owner-import-' + kind + '.csv';
let mimeType = 'text/csv';
if (!rows.length) {
  csv = 'message\nreport not found\n';
} else if (rows[0].section === 'error') {
  csv = 'message\n' + String(rows[0].message || 'report not found').replace(/\n/g, ' ') + '\n';
  fileName = 'owner-import-error.txt';
  mimeType = 'text/plain';
} else if (kind === 'summary') {
  const row = rows[0];
  csv = [
    'job_id,status,file_name,source_type,source_ref,total_rows,valid_rows,invalid_rows,ambiguous_rows,matched_rows,new_rows,applied_rows,failed_rows',
    [row.job_id, row.status, row.file_name, row.source_type, row.source_ref, row.total_rows, row.valid_rows, row.invalid_rows, row.ambiguous_rows, row.matched_rows, row.new_rows, row.applied_rows, row.failed_rows]
      .map((value) => '"' + String(value === undefined || value === null ? '' : value).replace(/"/g, '""') + '"')
      .join(','),
  ].join('\n') + '\n';
  fileName = 'owner-import-summary-' + String(d.job_id || 'job') + '.csv';
} else {
  const headers = ['row_no', 'chunk_no', 'match_status', 'apply_status', 'item_name', 'price', 'stock', 'target_sku', 'target_item_name', 'review_reason', 'error_reason'];
  csv = [headers.join(',')];
  for (const row of rows) {
    csv.push(headers.map((header) => '"' + String(row[header] === undefined || row[header] === null ? '' : row[header]).replace(/"/g, '""') + '"').join(','));
  }
  csv = csv.join('\n') + '\n';
  fileName = 'owner-import-' + kind + '-' + String(d.job_id || 'job') + '.csv';
}
return [{
  json: {
    ok: true,
    response_body: csv,
    file_name: fileName,
    content_type: mimeType + '; charset=utf-8',
  },
}];

